<div class="d-flex justify-content-between align-items-center mb-3 mobile-stack"><div><h1 class="page-title h3 mb-1">Kategori Kas</h1><div class="text-muted">Referensi kategori kas masuk dan kas keluar per UMKM.</div></div><a class="btn btn-primary" href="<?= e(url('index.php?page=referensi-kategori-kas-create')) ?>">Tambah Kategori Kas</a></div>
<div class="card enterprise-card"><div class="card-body p-0"><div class="table-responsive"><table class="table table-hover align-middle mb-0"><thead><tr><th width="60">No</th><th>Nama Kategori</th><th>Jenis</th><th>Keterangan</th><th width="170">Aksi</th></tr></thead><tbody><?php if(!$rows): ?><tr><td colspan="5" class="text-center text-muted py-4">Belum ada data.</td></tr><?php else: foreach($rows as $i=>$row): ?><tr><td><?= $i+1 ?></td><td class="fw-semibold"><?= e($row['nama_kategori']) ?></td><td><span class="badge text-bg-<?= $row['jenis']==='masuk' ? 'success':'warning' ?>"><?= e(ucfirst($row['jenis'])) ?></span></td><td><?= e($row['keterangan'] ?? '-') ?></td><td><div class="d-flex gap-2"><a class="btn btn-outline-primary btn-sm" href="<?= e(url('index.php?page=referensi-kategori-kas-edit&id='.(int)$row['id'])) ?>">Edit</a><form method="post" action="<?= e(url('index.php?page=referensi-kategori-kas-delete')) ?>" onsubmit="return confirm('Hapus kategori kas ini?')"><input type="hidden" name="_csrf" value="<?= e(csrf_token()) ?>"><input type="hidden" name="id" value="<?= (int)$row['id'] ?>"><button class="btn btn-outline-danger btn-sm">Hapus</button></form></div></td></tr><?php endforeach; endif; ?></tbody></table></div></div></div>